mapper.select:
SELECT reaction
FROM preference.user_place_reactions
WHERE user_id = CAST(#{userId} AS uuid)
	AND provider = #{provider}
	AND external_place_id = #{externalPlaceId}

SELECT CAST(id AS text)
FROM preference.user_saved_places
WHERE user_id = CAST(#{userId} AS uuid)
	AND provider = #{provider}
	AND external_place_id = #{externalPlaceId}

mapper.update:
UPDATE preference.user_saved_places
SET deleted_at = now()
WHERE user_id = CAST(#{userId} AS uuid)
	AND provider = #{provider}
	AND external_place_id = #{externalPlaceId}
	AND deleted_at IS NULL

mapper.select:

WHERE sp.user_id = CAST(#{userId} AS uuid)
	AND sp.deleted_at IS NULL
ORDER BY sp.created_at DESC, sp.id DESC
LIMIT #{limit}
OFFSET #{offset}
